Here is a complete, single-file HTML solution using **Three.js**. This code generates a procedural 3D house with a roof, walls, windows, and a door.

You can save the code below as an `.html` file (e.g., `house.html`) and open it in any modern web browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Model (Drag to rotate, Scroll to zoom)</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // --- 1. Scene Setup ---
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // --- 2. Lighting ---
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1.5);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // --- 3. Materials ---
        const materials = {
            wall: new THREE.MeshStandardMaterial({ color: 0xeeeeee }),
            roof: new THREE.MeshStandardMaterial({ color: 0x8B4513 }), // Brown
            grass: new THREE.MeshStandardMaterial({ color: 0x4caf50 }),
            window: new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 }),
            door: new THREE.MeshStandardMaterial({ color: 0x8B0000 }), // Dark Red
            wood: new THREE.MeshStandardMaterial({ color: 0x5D4037 })
        };

        // --- 4. Building the House ---
        const houseGroup = new THREE.Group();
        scene.add(houseGroup);

        // A. Ground
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const ground = new THREE.Mesh(groundGeo, materials.grass);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // B. Main Body (Cube)
        const bodyGeo = new THREE.BoxGeometry(8, 6, 8);
        const body = new THREE.Mesh(bodyGeo, materials.wall);
        body.position.y = 3; // Sit on top of ground
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // C. Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(7, 4, 4); // 4 sides
        const roof = new THREE.Mesh(roofGeo, materials.roof);
        roof.position.y = 8; // Center height + half height
        roof.rotation.y = Math.PI / 4; // Align square base
        roof.castShadow = true;
        houseGroup.add(roof);

        // D. Windows (Helper function)
        function createWindow(x, y, z, width, height) {
            const winGeo = new THREE.BoxGeometry(width, height, 0.2);
            const win = new THREE.Mesh(winGeo, materials.window);
            win.position.set(x, y, z);
            win.castShadow = true;
            houseGroup.add(win);
        }

        // Front Windows
        createWindow(-2, 4, 4, 1.5, 2);
        createWindow(2, 4, 4, 1.5, 2);

        // Side Windows
        createWindow(0, 4, -4, 2, 1.5);

        // E. Door
        const doorGeo = new THREE.BoxGeometry(1.5, 3, 0.2);
        const door = new THREE.Mesh(doorGeo, materials.door);
        door.position.set(0, 2.5, 4);
        door.castShadow = true;
        houseGroup.add(door);

        // F. Chimney
        const chimneyGeo = new THREE.BoxGeometry(1, 3, 1);
        const chimney = new THREE.Mesh(chimneyGeo, materials.wall);
        chimney.position.set(3, 10, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        // --- 5. Controls & Animation ---
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.dampingFactor = 0.05;
        controls.maxPolarAngle = Math.PI / 2 - 0.1; // Prevent going under ground

        // Handle Window Resize
        window.addEventListener('resize', onWindowResize, false);

        function onWindowResize() {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        }

        // Render Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  Copy the code block above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in your browser.

### Features included:
*   **Procedural Geometry:** The house is built using basic geometric shapes (Box, Cone, Plane) combined into a group.
*   **Lighting & Shadows:** Includes a directional light that casts realistic shadows on the ground and the house itself.
*   **Interactivity:** You can **click and drag** to rotate around the house, and **scroll** to zoom in and out.
*   **Details:** Includes a chimney, a door, and windows with transparency.
